#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long ans = (Y - 1) / X;
        if (ans < 0) ans = 0; // safety, though not needed with given constraints
        printf("%lld\n", ans);
    }
    return 0;
}

